compliant:
class Base {
private:
  int value; // Compliant: private member variable
  std::string data;
public:
  Base(int v) : value(v) {}
  int getValue() const { return value; } // Controlled access
  void setValue(int v) { value = v; } // Controlled modification
};

class Configuration {
private:
  bool enabled; // Compliant: encapsulated
  int maxRetries;
public:
  bool isEnabled() const { return enabled; } // Controlled access
  void setEnabled(bool e) { enabled = e; } // Controlled modification
};

class Vehicle {
private:
  double speed; // Compliant: proper encapsulation
  int wheels;
protected:
  // Protected methods for derived classes
  void setSpeed(double s) { speed = s; }
  double getSpeed() const { return speed; }
};
